{
  "analysis": "Intermittent fasting (IF) in metabolic syndrome has a mature evidence base spanning RCTs, systematic reviews, and mechanistic studies, plus regulatory caution, growing consumer market, and emerging circadian/microbiome research. Seed queries must span hard clinical efficacy evidence, safety/regulatory stance, commercial landscape, cost-effectiveness, population epidemiology, historical origins, regional patterns, methodological rigor in IF trials, and emerging biology. Target high-quality sources: meta-analyses and systematic reviews for Scientific/Methodological, regulatory agency guidance for Regulatory, market research for Industry, health-economic journals for Economic, long-horizon cohorts for Public_Health.",
  "sub_queries": [
    {
      "query": "intermittent fasting metabolic syndrome systematic review meta-analysis randomized controlled trial cardiometabolic outcomes HbA1c insulin resistance",
      "intent": "Find the highest-tier clinical efficacy and safety evidence from systematic reviews and RCTs on IF specifically in metabolic syndrome populations",
      "source_preference": "academic",
      "perspective": "Scientific"
    },
    {
      "query": "FDA EMA dietary intervention therapeutic claim intermittent fasting guidance position statement",
      "intent": "Identify formal regulatory positions, guidance documents, and any enforcement actions relating to IF as a therapeutic intervention for metabolic disease",
      "source_preference": "both",
      "perspective": "Regulatory"
    },
    {
      "query": "intermittent fasting app Zero Fastic LIFE Simple subscription revenue market size commercial wellness industry report",
      "intent": "Map the commercial IF product landscape — apps, programs, manufacturers, market sizing, and industry reports that reveal real-world usage and product claims",
      "source_preference": "web",
      "perspective": "Industry"
    },
    {
      "query": "intermittent fasting cost-effectiveness QALY lifestyle intervention metabolic syndrome type 2 diabetes health economic evaluation",
      "intent": "Find cost-effectiveness and health-economic analyses comparing IF against standard of care, pharmacotherapy, and other lifestyle interventions",
      "source_preference": "web",
      "perspective": "Economic"
    },
    {
      "query": "intermittent fasting time restricted eating epidemiology long term cardiovascular mortality population cohort NHANES",
      "intent": "Find population-level epidemiological evidence on IF exposure and long-term health outcomes, including any signals of harm",
      "source_preference": "both",
      "perspective": "Public_Health"
    },
    {
      "query": "intermittent fasting history Ramadan fasting physiological research Longo Mattson landmark studies timeline development",
      "intent": "Trace the biomedical origins and pivotal papers that established modern IF research, from religious fasting physiology through to Longo and Mattson laboratory work",
      "source_preference": "academic",
      "perspective": "Historical"
    },
    {
      "query": "intermittent fasting cultural adoption Ramadan Mediterranean Asia United States regional differences prevalence dietary pattern",
      "intent": "Compare regional adoption patterns, cultural context, and how prevalence varies by geography — important for generalizability of findings",
      "source_preference": "web",
      "perspective": "Regional"
    },
    {
      "query": "intermittent fasting clinical trial methodology study design adherence measurement self report bias CONSORT",
      "intent": "Examine methodological rigor in IF trials — adherence measurement, self-report bias, CONSORT adherence, and how study quality affects the evidence base",
      "source_preference": "academic",
      "perspective": "Methodological"
    },
    {
      "query": "intermittent fasting circadian biology gut microbiome longevity autophagy recent research 2024 2025 breakthrough",
      "intent": "Identify emerging research on circadian timing, gut microbiome effects, autophagy, and other mechanistic frontiers that are reshaping our understanding of IF",
      "source_preference": "web",
      "perspective": "Emerging_Trends"
    }
  ]
}
